11→class PostSettingsUtils
12→@Inject constructor(
13→    private val resourceProvider: ResourceProvider,
14→    private val statsDateUtils: StatsDateUtils,
15→    private val postUtilsWrapper: PostUtilsWrapper
16→) {
17→    fun getPublishDateLabel(
18→        postModel: PostImmutableModel
19→    ): String {
20→        val labelToUse: String
21→        val dateCreated = postModel.dateCreated
22→        val status = PostStatus.fromPost(postModel)
23→        if (!TextUtils.isEmpty(dateCreated)) {
24→            val formattedDate = statsDateUtils.formatDateTime(dateCreated)
25→
26→            if (postModel.isLocalDraft) {
27→                if (postUtilsWrapper.isPublishDateInThePast(postModel.dateCreated)) {
28→                    labelToUse = resourceProvider.getString(R.string.backdated_for, formattedDate)
29→                } else if (postUtilsWrapper.isPublishDateInTheFuture(postModel.dateCreated)) {
30→                    labelToUse = resourceProvider.getString(R.string.schedule_for, formattedDate)
31→                } else if (postUtilsWrapper.shouldPublishImmediately(status, postModel.dateCreated)) {
32→                    labelToUse = resourceProvider.getString(R.string.immediately)
33→                } else {
34→                    labelToUse = resourceProvider.getString(R.string.publish_on, formattedDate)
35→                }
36→            } else if (status == PostStatus.SCHEDULED) {
37→                labelToUse = resourceProvider.getString(R.string.scheduled_for, formattedDate)
38→            } else if (status == PostStatus.PUBLISHED || status == PostStatus.PRIVATE) {
39→                labelToUse = resourceProvider.getString(R.string.published_on, formattedDate)
40→            } else if (postUtilsWrapper.isPublishDateInTheFuture(postModel.dateCreated)) {
41→                labelToUse = resourceProvider.getString(R.string.schedule_for, formattedDate)
42→            } else {
43→                labelToUse = resourceProvider.getString(R.string.publish_on, formattedDate)
44→            }
45→        } else if (postUtilsWrapper.shouldPublishImmediatelyOptionBeAvailable(status)) {
46→            labelToUse = resourceProvider.getString(R.string.immediately)
47→        } else {
48→            labelToUse = resourceProvider.getString(R.string.immediately)
49→        }
50→        return labelToUse
51→    }
52→}
